animations.cssText:
@keyframes gradientFlow { 
  0% { background-position: 0% center; }
  50% { background-position: 100% center; }
  100% { background-position: 0% center; }
}

@keyframes gradient-button { 
  0% { background-position: 0% center; }
  50% { background-position: 100% 0px; }
  100% { background-position: 0% center; }
}

@keyframes vds-menu-enter { 
  0% { opacity: 0; transform: var(--exit-transform); }
  100% { opacity: 1; transform: var(--enter-transform); }
}

@keyframes vds-menu-exit { 
  0% { opacity: 1; transform: var(--enter-transform); }
  100% { opacity: 0; transform: var(--exit-transform); }
}

@keyframes vds-slider-icon { 
  0% { transform: scale(1); }
  50% { transform: scale(1.25); }
  100% { transform: scale(1); }
}

@keyframes vds-tooltip-enter { 
  0% { opacity: 0; transform: var(--exit-transform); }
  100% { opacity: 1; transform: var(--enter-transform); }
}

@keyframes vds-tooltip-exit { 
  0% { opacity: 1; transform: var(--enter-transform); }
  100% { opacity: 0; transform: var(--exit-transform); }
}

@keyframes plyr-popup { 
  0% { opacity: 0.5; transform: translateY(10px); }
  100% { opacity: 1; transform: translateY(0px); }
}

